"""
MKT Context Commentary — Joshua chapters 18–20
Run: python3 scripts/zc-context-joshua-18-20.py

Source data used:
- data/interlinear/joshua.json
- data/translation/draft/mediating/joshua.json

Key decisions in this range:
- Shiloh (ch18:1): the tabernacle's relocation from Gilgal to Shiloh is treated as a
  major institutional shift — Shiloh becomes the pre-monarchic national sanctuary
- The survey document (ch18:4-9): the written land description is treated as an
  administrative innovation with ANE parallels
- Blood avenger / gōʾēl haddām (ch20): the kinship-justice system fully explained;
  the high priest's death as release mechanism is the theologically weightiest detail
- Dan's migration (ch19:47): briefly noted as foreshadowing Judges 18
- Simeon's absorption into Judah (ch19:1,9): the administrative reality explained
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

JOSHUA = {
  "18": {
    "1": "<p>Shiloh becomes the new headquarters for the allotment process — a significant institutional shift from Gilgal (the military base camp). Shiloh (Khirbet Seilun) is located in the central hill country of Ephraim, roughly equidistant from the northern and southern tribes. Its elevation (~870m) and natural defensibility made it a suitable permanent cultic center. Archaeological excavations at the site confirm significant Late Bronze Age / Iron Age I occupation. Shiloh functions as Israel's central sanctuary from Joshua through the fall of the ark to the Philistines (1 Sam 4) — a period of roughly 150-200 years. Psalm 78:60 describes YHWH 'abandoning his tabernacle at Shiloh'; Jeremiah invokes Shiloh's destruction as the template for what YHWH will do to Jerusalem (Jer 7:12-14; 26:6). The move from Gilgal to Shiloh marks the transition from conquest-mode to settlement-mode administration.</p>",
    "2": "<p>Seven tribes without allotment — over halfway through the distribution, more than half the tribes are still waiting. The delay reflects a real social phenomenon: once security was partially established, the urgency of completing the distribution diminished. The two tribes already settled (Judah, Ephraim/Manasseh) were politically dominant; the smaller tribes had less leverage to demand prompt action. Joshua's rebuke in v.3 suggests the delay was not logistical but motivational.</p>",
    "3": "<p>'How long will you put off going in to claim the land?' The verb <em>hitrappôt</em> (put off, be slack, procrastinate) identifies the problem as spiritual lethargy, not military inability. The land has been subdued (v.1); the only barrier is Israel's failure to advance and occupy. This pattern — YHWH's gift given but not received — runs throughout the allotment chapters and anticipates the judges period, where Israel repeatedly fails to complete what Joshua started.</p>",
    "4": "<p>Joshua commissions a professional survey: three men per tribe from the seven remaining tribes = twenty-one surveyors. The instruction to 'write a description' (<em>kĕtāb-lî et-hāʾāreṣ</em>) of the land is remarkable — it implies a written geographic document, the first Israelite cadastral survey (land registry). ANE parallels exist: Egyptian land surveys ('Wilbour Papyrus'), Mesopotamian field plans drawn on clay tablets. The survey format Joshua prescribes — dividing into seven sections for seven tribes — follows the administrative logic of proportional distribution.</p>",
    "5": "<p>The survey framework: Judah (already allotted) holds the south; the house of Joseph (already allotted) holds the north; the seven remaining tribes fill the middle. The geographical logic places Benjamin as the buffer tribe between Judah and Joseph — a position that will define Benjaminite identity for the rest of the OT. The tribe of Saul (1 Sam 9:1-2) occupies the hinge between Israel's two dominant tribes.</p>",
    "6": "<p>'I will cast lots for you here before the LORD our God.' The lot (<em>gôrāl</em>) before YHWH at the sanctuary is an oracular procedure, not a random lottery. The Urim and Thummim (Exod 28:30; Num 27:21) and the priestly lot were standard mechanisms for divine decision-making in ancient Israel. Shiloh as the lot-casting site grounds the distribution in Yahwistic worship; the land is received as a gift discerned through divine oracle, not merely allocated by human administrative judgment.</p>",
    "7": "<p>Levi's exception is restated alongside the trans-Jordan tribes' settled status. The double exclusion (Levi: no territory because YHWH is their inheritance; trans-Jordan tribes: already settled by Mosaic grant) clarifies the scope of what remains. The Levitical cities (ch.21) will be carved out of other tribes' allotments — Levi's 'inheritance' is distributed presence throughout all Israel, not a territorial block.</p>",
    "8": "<p>The surveyors depart with instructions to 'write a description' and return. Joshua's command at Shiloh mirrors Moses's instruction at Sinai — both give the people a task to complete before receiving YHWH's decision. The survey is Israel's active participation in their own allotment: YHWH casts the lots, but Israel does the geographic reconnaissance. The partnership of divine sovereignty (lot) and human diligence (survey) is characteristic of the book's theology.</p>",
    "9": "<p>'The men went and traveled through the land, mapping it town by town in seven sections, in a document.' The written document (<em>bĕsēper</em>) produced from the survey is one of the oldest written geographic records mentioned in the OT. The phrase 'town by town' suggests a systematic settlement-by-settlement inventory rather than a simple boundary description — more like a population and settlement census than a surveyor's map. Some scholars have proposed that the city lists of chs.15-19 derive from this survey document, preserved in the tribal archives and later incorporated into Joshua.</p>",
    "10": "<p>At Shiloh, before YHWH, Joshua casts the lots. The procedure is complete: survey done, lots cast, allotments determined. The entire process — Eleazar the priest, Joshua the commander, the tribal elders, the survey teams, the lot — represents the most elaborate administrative procedure in the book. The care invested in the distribution reflects its theological weight: this is not real estate transaction but covenant inheritance being formally transferred from YHWH to his people.</p>",
    "11": "<p>Benjamin's lot falls between Judah and Joseph — geographically precise and politically significant. Benjamin was the youngest son of Jacob (Gen 35:18), the only son born in Canaan, and the brother Joseph most cherished (Gen 43:29). The tribe's small territory between Israel's two dominant tribes shapes its entire subsequent history: it is the contested middle ground in the Joseph-Judah tension that persists through the monarchy.</p>",
    "12": "<p>Benjamin's northern boundary follows the Jordan from the Dead Sea and runs west through the Beth-aven wilderness. The 'shoulder of Jericho on the north' places Benjamin's boundary just above Jericho — the first conquered city. Jericho's ruined site (under YHWH's curse, Josh 6:26) formed an unmistakable boundary landmark in the landscape.</p>",
    "13": "<p>Bethel/Luz — a key boundary point. Bethel's dual name (Canaanite Luz; Israelite Bethel, 'house of God') reflects the palimpsest of place-names in Canaan, where each conquest created a new naming layer over the old. Bethel sits on the Benjamin-Ephraim boundary, explaining its contested religious status: both tribes could claim association with the patriarchal site. Jeroboam later places a golden calf there (1 Kgs 12:29) partly because its liminal position made it accessible to northern Israelites without requiring a journey through Judah to Jerusalem.</p>",
    "14": "<p>The boundary turns south along the western slope of the Bethel highlands. Kiriath-baal/Kiriath-jearim (already noted in Judah's boundary at 15:9,60) appears as a shared landmark on the Judah-Benjamin line — the city's administrative importance as a boundary point and its future role as the ark's home (1 Sam 7:1) are both implied by its prominence in the boundary descriptions.</p>",
    "15": "<p>The southern boundary of Benjamin runs from Kiriath-jearim to the spring of Nephtoah — the same western section of Judah's northern boundary described in 15:9 in reverse. Boundary descriptions often trace the same line from opposite directions, one tribe's northern boundary being another's southern; the consistency confirms the survey's systematic character.</p>",
    "16": "<p>The Valley of Ben-hinnom again — appearing as Benjamin's southern boundary feature as it did in Judah's northern boundary (15:8). The valley ran between Jerusalem (a Benjaminite city in this allotment, v.28) and Judah's territory. Benjamin's ownership of Jerusalem in the allotment system — while Judah's failure notice (15:63) says Judah couldn't dislodge the Jebusites — is one of the apparent inconsistencies between the idealized allotment and historical reality; both Judg 1:21 (Benjamin) and 1:8 (Judah) address Jerusalem's status.</p>",
    "17": "<p>En-shemesh and En-rogel mark the eastern end of the southern boundary before the descent to the Jordan valley. En-rogel ('spring of the fuller') is the site where Adonijah held his coronation feast (1 Kgs 1:9) and where Jonathan and Ahimaaz hid as David's intelligence operatives during Absalom's revolt (2 Sam 17:17). The spring's position just outside Jerusalem's walls made it a recurring location for politically sensitive meetings.</p>",
    "18": "<p>The boundary crosses to the northern slope of Beth-arabah and descends to the Arabah — the Jordan rift valley floor. The 'shoulder of Beth-arabah' names a topographic feature (a ridge shoulder or saddle) that served as a surveyor's landmark, confirming the boundary descriptions' basis in actual terrain features rather than schematic geography.</p>",
    "19": "<p>The boundary terminates at the bay of the Dead Sea at the mouth of the Jordan — the same point where Judah's eastern boundary began (15:5). Benjamin's southern boundary closes perfectly against Judah's northern one; the two allotments are administratively seamless. This precision is the mark of a real survey, not literary invention.</p>",
    "20": "<p>The Jordan completes Benjamin's eastern boundary, enclosing the territory. Benjamin's small size — roughly a triangle between Jerusalem, Jericho, and Bethel — belies its strategic importance. This terrain contains the main ridge road (the 'Way of the Patriarchs'), the passes to the Jordan valley, and Jerusalem's approaches; whoever holds Benjamin controls the country's spine.</p>",
    "21": "<p>Benjamin's city list begins: Jericho (the entry point of the conquest, now a ruined landmark under Joshua's curse), Beth-hoglah, Emek-keziz — the Jordan valley floor settlements. The cursed city of Jericho (Josh 6:26) appearing in a city list without commentary on its ruined state is noteworthy; it is listed as a possession, presumably referring to the region rather than the city itself.</p>",
    "22": "<p>Beth-arabah, Zemaraim, Bethel — the transition from Jordan valley to hill country. Bethel appears in Benjamin's city list (not just as a boundary marker), confirming that the city itself belonged to Benjamin while the boundary ran through its vicinity. Bethel's later history under Jeroboam takes on a different valence when one realizes it was a Benjaminite city that the northern king appropriated for his political-religious program.</p>",
    "23": "<p>Avvim, Parah, Ophrah — the eastern Benjamin hill country. Ophrah is associated with Gideon in Judges (Judg 6:11,24; 8:27), suggesting a different Ophrah than this Benjaminite city, or that this territory shifted between administrative periods. The overlap of place names in different contexts is a recurring challenge in reading the allotment and judges narratives together.</p>",
    "24": "<p>Chephar-ammoni, Ophni, Geba — twelve cities in this first Benjamin grouping. Geba is a key border fortress between Benjamin and Ephraim; it is garrisoned by Philistines at the start of Saul's campaign (1 Sam 13:3) and Jonathan attacks it in the opening move of the liberation war. The allotment geography maps the precise terrain of Saul and Jonathan's campaigns.</p>",
    "25": "<p>Gibeon, Ramah, Beeroth — three significant cities. Gibeon is the Hivite city from ch.9 whose deception secured a treaty with Israel; its inclusion in Benjamin's allotment explains how the Gibeonite treaty became a Benjaminite responsibility. Ramah ('high place') is Samuel's hometown and burial site (1 Sam 1:19; 25:1) — the prophet who anointed both Saul and David lived in Benjamin's territory. Rachel's tomb at Ramah (Jer 31:15; Matt 2:18) is the maternal grief-site for all the northern exile.</p>",
    "26": "<p>Mizpah, Chephirah, Mozah — Mizpah ('watchtower') in Benjamin is a key site: Samuel judges Israel there (1 Sam 7:5-17), Saul is chosen king there by lot (1 Sam 10:17-24), and the Babylonians make it the post-destruction capital of Judah (Jer 40:5-12; 41:1-3). The allotment assigns to Benjamin the future administrative center of the province of Judah. Chephirah is one of the Gibeonite four-city league (Josh 9:17) — another Hivite city absorbed into Benjaminite territory.</p>",
    "27": "<p>Rekem, Irpeel, Taralah — minor Benjaminite sites. The preservation of otherwise unknown place names in the official record continues the pattern: these are genuine archival data, not a literary invention that would have named only known sites.</p>",
    "28": "<p>Zelah, Haeleph, Jebus (Jerusalem), Gibeah, Kiriath — fourteen cities close the Benjamin list. Two of the most theologically significant locations in the OT: Jerusalem (<em>yĕbûs</em>/Jebus, the pre-Davidic name) and Gibeah. Jerusalem is Benjamin's city in the allotment, though unoccupied; David will capture it and make it his capital, technically holding a Benjaminite city. Gibeah (<em>gibeʿāh</em>) is Saul's hometown (1 Sam 10:26; 15:34) and the site of the Levite concubine's gang-rape (Judg 19) — one of the Bible's most horrific narratives is rooted in the allotment geography.</p>"
  },
  "19": {
    "1": "<p>Simeon's allotment is embedded within Judah's territory — the only tribe without a geographically distinct territory. This unusual arrangement has a historical background: Jacob's deathbed curse on Simeon and Levi for the Shechem massacre (Gen 34; Gen 49:5-7 — 'I will scatter them in Jacob and disperse them in Israel') is fulfilled here: Levi is scattered as a landless priestly tribe, and Simeon is absorbed within Judah's territory. The curse shapes the allotment.</p>",
    "2": "<p>Simeon's cities begin with Beersheba — the patriarchal boundary site (Gen 21:31-33; 26:33), the southern limit of the promised land ('from Dan to Beersheba'). Simeon's territory at the very south of Canaan placed the tribe in the most exposed position, facing Edomite and nomadic pressure; the combination of exposure and absorption into Judah explains why Simeon essentially disappears as a distinct entity after the early monarchy. 1 Chronicles 4:24-43 preserves a late tradition of Simeonite expansion into the Negev and Seir, suggesting some Simeonites maintained a separate tribal identity by migrating further south and east.</p>",
    "3": "<p>Hazar-shual, Balah, Azem — Negev frontier sites. The same cities appear in Judah's Negev list (15:28-29), confirming the overlap between Simeon's allotment and Judah's claimed territory. The administrative solution was pragmatic: Simeon was given title to cities within Judah's over-large claim, effectively forming an enclave with no border of its own.</p>",
    "4": "<p>Eltolad, Bethul, Hormah — again overlapping with Judah's city list (15:30). The three-way overlap (Simeon's list / Judah's list / Simeon within Judah's boundary) is not an editorial inconsistency but a reflection of a real administrative situation: Simeon held specific cities as its allotment while Judah held the surrounding territory and overall jurisdiction.</p>",
    "5": "<p>Ziklag — mentioned in both Simeon's and Judah's lists. This is the Philistine-controlled city that Achish gave David as his residence during the Saul years (1 Sam 27:6), with the narrator noting 'it has belonged to the kings of Judah to this day.' The Davidic royal claim to Ziklag — bypassing both Simeon's original title and Philistine occupation — illustrates how the allotment system interacted with military conquest and royal grant in the later monarchy.</p>",
    "6": "<p>Beth-lebaoth, Sharuhen — the list approaches the Gaza corridor and Philistine territory. Sharuhen (Tell el-Farah South) is archaeologically significant as an Egyptian administrative site in the Negev; its inclusion in Simeon's allotment acknowledges a region that was politically contested between Egypt, Philistia, and Israel throughout the early Iron Age.</p>",
    "7": "<p>Ain, Rimmon, Ether, Ashan — four cities closing the first group. Rimmon appears in Neh 11:29 as a post-exilic settlement, confirming that Simeonite/southern Judean towns were still recognized as distinct settlements even after the Babylonian exile and return.</p>",
    "8": "<p>All the surrounding villages including Baalath-beer/Ramah of the Negev. The phrase 'all the villages surrounding these cities as far as Baalath-beer' indicates that the allotment includes both the named cities and their agricultural hinterlands. Baalath-beer ('mistress of the well') preserves a Canaanite female deity's name; the southern Negev place-names reflect the Canaanite, Amalekite, and nomadic cultures that had inhabited this zone for centuries before Israel.</p>",
    "9": "<p>'The inheritance of Simeon was taken from the allotment of Judah, because Judah's share was too large for them.' This administrative note is unusual — it acknowledges that the lot-based allotment required post-hoc adjustment when Judah's allocation proved oversized. The lot determined territorial ownership, but the boundaries were set by human survey; the discrepancy required correction. This also confirms that the lot system was not mechanically applied without regard for demographic realities: the process included administrative flexibility.</p>",
    "10": "<p>Zebulun's allotment: the Galilee hill country south of the Nazareth ridge. Zebulun's territory is relatively small and landlocked (despite Gen 49:13 suggesting a coastal orientation — 'Zebulun shall live by the seashore'). The gap between Jacob's blessing and the allotment is sometimes noted; the blessing may anticipate a later expansion toward the coast that never fully materialized. Isaiah 9:1-2 calls this territory 'Galilee of the Gentiles,' the region of darkness where a great light appears — applied in Matt 4:13-16 to Jesus's Galilean ministry. Nazareth, Jesus's hometown, was in Zebulun's territory.</p>",
    "11": "<p>Zebulun's boundary runs to Sarid, then west. The specific location of Sarid is uncertain but was in the plain south of the Nazareth ridge — the transition zone between the Jezreel Valley and the Galilean highlands. Maralah and Dabbesheth appear only here; the unusual place names suggest authentic archival material from a survey document that preserved local names now otherwise lost.</p>",
    "12": "<p>Eastward from Sarid to Chisloth-tabor and Daberath — the boundary approaches Mount Tabor, the dominant peak of the lower Galilee region. Mount Tabor (Judg 4:6,12,14) was Deborah and Barak's staging point for the battle against Sisera — Zebulun's territory encompassed the command position for Israel's great Galilean victory against the Canaanite coalition.</p>",
    "13": "<p>From Gath-hepher to Eth-kazin and Rimmon — the northern Zebulun boundary. Gath-hepher is identified as the hometown of the prophet Jonah (2 Kgs 14:25) — the prophet commanded to preach to Nineveh came from Zebulun, the most ethnically mixed region of Israel ('Galilee of the Gentiles'). The geographic connection between Jonah's Galilean background and his mission to the nations is narratively significant.</p>",
    "14": "<p>The boundary circles around to Hannathon and ends at the Valley of Iphtah-el. The 'turning' (<em>sābab</em>) of the boundary at the northern point follows the valley system; Hannathon appears in the el-Amarna letters (14th century BCE) as a Canaanite city under Egyptian administration — 'Hinnatuna' — confirming the archival depth of these place names.</p>",
    "15": "<p>Kattath, Nahalal, Shimron, Idalah, Bethlehem — twelve cities for Zebulun. This Bethlehem is the Galilean Bethlehem (Judg 17:7-9 refers to a Levite 'from Bethlehem in Judah' who stayed at 'Bethlehem in Zebulun') — a less famous namesake of the Judean Bethlehem. The existence of a northern Bethlehem ('house of bread') alongside the southern one reflects the common Semitic naming pattern for agricultural settlements.</p>",
    "16": "<p>Zebulun's allotment formula closes the section. The subsequent history of Zebulun in the book of Judges is one of the more active: Zebulun contributes troops to Deborah's battle (Judg 4:10; 5:14,18 — 'Zebulun is a people who risked their lives to the point of death'), and Elon the Zebulunite is a minor judge (Judg 12:11). The small allotment produced a consistently active tribe.</p>",
    "17": "<p>Issachar's allotment: the Jezreel Valley and its approaches. Issachar's territory is dominated by the Jezreel ('God sows') Valley, the most fertile agricultural plain in Canaan. Egypt maintained administrative control over the Jezreel throughout the Late Bronze Age (the el-Amarna letters show extensive Egyptian oversight of Megiddo, Beth-shean, and other Jezreel cities); the transition to Israelite administration was gradual and contested.</p>",
    "18": "<p>Jezreel, Chesulloth, Shunem — key sites. Jezreel gave its name to the valley; it became Ahab's summer residence (1 Kgs 21:1) and the site of Naboth's vineyard (1 Kgs 21:1-16), Jehu's coup (2 Kgs 9:14-37), and Hosea's judgment oracle (Hos 1:4-5). Shunem was the home of the 'great woman' whose son Elisha raised from the dead (2 Kgs 4:8-37) and where Abishag the Shunammite came from (1 Kgs 1:3). Issachar's cities were sites of some of the OT's most dramatic narratives.</p>",
    "19": "<p>Hapharaim, Shion, Anaharath — Jezreel valley sites. The valley floor was proverbially fertile; Issachar's territory was agriculturally rich but militarily exposed on all sides. Jacob's blessing suggests Issachar chose agricultural stability over independence: 'Issachar is a strong donkey... when he saw that his resting place was good and the land was pleasant, he bent his shoulder to bear the load and became a slave laborer' (Gen 49:14-15) — an uncomplimentary assessment of a tribe that traded military autonomy for agricultural prosperity.</p>",
    "20": "<p>Rabbith, Kishion, Ebez — southern Issachar. These minor sites mark the transition from the Jezreel plain to the hill country; the southern boundary of Issachar is where the valley meets the Manassite hills, explaining the tension between the two tribes over specific valley cities (Josh 17:10-11).</p>",
    "21": "<p>Remeth, En-gannim, En-haddah, Beth-pazzez — the eastern Issachar sites toward the Jordan valley. En-gannim ('spring of gardens') reflects the irrigation agriculture that made the eastern Jezreel Valley productive; garden-spring toponyms cluster in well-watered zones throughout the OT, marking the intersection of water and settlement.</p>",
    "22": "<p>The boundary reaches Tabor, Shahazumah, and Beth-shemesh (a northern Beth-shemesh, distinct from the Judean one), ending at the Jordan — sixteen cities for Issachar. Tabor appearing again (as a boundary marker shared with Zebulun) confirms that Mount Tabor served as the administrative landmark at the intersection of three tribal territories: Zebulun, Issachar, and Naphtali.</p>",
    "23": "<p>Issachar's allotment formula. The tribe's later prominence includes Tola son of Puah, an Issacharite judge (Judg 10:1-2), and Baasha king of Israel (1 Kgs 15:27) — an Issacharite who seized the throne from Jeroboam's dynasty by assassination, suggesting that Issachar's agricultural wealth eventually translated into political ambition.</p>",
    "24": "<p>Asher's allotment: the western Galilee coastal strip, one of the most desirable territories in Canaan. The Phoenician coast was known for its timber (Lebanon cedar), purple dye (murex snails), and maritime trade. Asher's territory should have made it the wealthiest tribe; the failure notices (Judg 1:31-32) showing Asher living among the Canaanites rather than displacing them suggest the Asherites either lacked the military capacity or chose to coexist with the Phoenician urban populations rather than displace them.</p>",
    "25": "<p>Helkath, Hali, Beten, Achshaph — the inner Asher coast. Achshaph was a major Canaanite city-state whose king fought against Joshua in the northern campaign (Josh 11:1; 12:20). Its inclusion in Asher's city list without comment on its continued Canaanite occupation anticipates Judg 1:31.</p>",
    "26": "<p>Alammelech, Amad, Mishal — the boundary approaches Carmel. Mount Carmel's promontory into the Mediterranean forms the major geographic feature of Asher's southern boundary; it separates the Asher coast (north) from the Manassite coast (south). Carmel's later fame as Elijah's confrontation site (1 Kgs 18) is rooted in its being the frontier between Asher, Manasseh, and the Jezreel.</p>",
    "27": "<p>The boundary turns to Beth-dagon, Zebulun, and the Valley of Iphtah-el. Beth-dagon ('house of Dagon') appears in both Asher's and Judah's allotments, reflecting the widespread distribution of Dagon-worship sites throughout Canaan. The Dagon-cult was not exclusively Philistine but was broadly Semitic; the place names preserve the religious geography of pre-Israelite Canaan.</p>",
    "28": "<p>Ebron, Rehob, Hammon, Kanah, and Greater Sidon. The appearance of Sidon in Asher's boundary reflects the ambitious scope of the allotment: Sidon was the principal Phoenician city-state, never incorporated into Israel. The text's inclusion of Sidon in the theoretical boundary while the Canaanites of the actual territory were never expelled (Judg 1:31) illustrates the persistent gap between ideal and actual possession.</p>",
    "29": "<p>The boundary returns through Ramah to Tyre and Hosah, ending at the sea near Aczib — twenty-two cities for Asher. Tyre, like Sidon, was never conquered; its inclusion marks the northern extent of the theoretical grant. The Tyre-Sidon coast later becomes the Syro-Phoenician region where Jesus heals the Canaanite woman's daughter (Matt 15:21-28; Mark 7:24-30) — the land that Israel never possessed becomes the place where the Gentile mission begins.</p>",
    "30": "<p>Ummah, Aphek, Rehob — twenty-two cities total for Asher. Aphek on the Asher coast (distinct from the Jordan valley Aphek) was a Phoenician city; its appearance in the list confirms the theoretical scope. The failure to possess these coastal cities created the long-term Phoenician corridor separating the Israelite northern tribes from the sea — Israel remained essentially a land power throughout the monarchy because Asher never fulfilled its allotment.</p>",
    "31": "<p>Asher's allotment formula. The tribe's later history in Judges is conspicuously absent from the liberation narratives; Asher is criticized in Deborah's song for staying 'by the seashore, settling in its coves' (Judg 5:17) during the crisis against Sisera — the comfortable coastal tribe did not mobilize. Anna the prophetess (Luke 2:36-38) is from the tribe of Asher — the only Asherite named in the NT, living in Jerusalem and waiting for the consolation of Israel.</p>",
    "32": "<p>Naphtali's allotment: the upper Galilee and Sea of Galilee basin. This is the territory of the Galilee heartland — the region of Jesus's ministry. Capernaum, the base of Jesus's Galilean operations, was in Naphtali (Matt 4:13 places it in 'the region of Zebulun and Naphtali'); Isaiah 9:1-2's promise of light in these two northern tribes is explicitly applied to Jesus's ministry.</p>",
    "33": "<p>Naphtali's boundary from Heleph to the oak of Zaanannim near Kedesh — the oak (<em>ʾallôn</em>) in the boundary description is the same landmark used in Deborah's narrative (Judg 4:11: 'near the oak of Zaanannim near Kedesh'). Heber the Kenite camped there; the exact landmark preserved in the allotment boundary reappears in the battle narrative of Judges 4, confirming the geographic precision of both texts.</p>",
    "34": "<p>The boundary connects Aznoth-tabor and runs to Hukkok, touching Zebulun to the south and Asher to the west, with Judah on the Jordan to the east. 'Judah on the Jordan' is textually disputed — Judah's territory doesn't extend to the upper Jordan; the text may reference a clan or district called 'Judah' in the upper Jordan area, or it may be a scribal error. The boundary description accurately defines Naphtali's triangular territory between the Sea of Galilee, upper Jordan, and the Galilean highlands.</p>",
    "35": "<p>Naphtali's fortified cities: Ziddim, Zer, Hammath, Rakkath, Kinnereth. Kinnereth gave its name to the Sea of Kinnereth (= Sea of Galilee); the city sat on the northwestern shore. Hammath ('hot springs') near Tiberias is attested by archaeological remains; its name reflects the geothermal springs along the western Sea of Galilee shore that made the region distinctive. Rakkath is identified with Tiberias by the Talmud — the city Herod Antipas founded and named for the Roman emperor.</p>",
    "36": "<p>Adamah, Ramah, Hazor — northern Naphtali. Hazor appears again (already destroyed in ch.11 and listed as a conquered city in ch.12); its inclusion in Naphtali's allotment confirms that the city's territory was assigned even though the city itself had been burned. Jabin king of Hazor (Judg 4:2) suggests either Canaanite reoccupation of the site or a separate ruler who inherited the Hazor name/title.</p>",
    "37": "<p>Kedesh, Edrei, En-hazor — the sites approaching the Syrian plateau. Kedesh in Galilee is the prominent northern city of refuge (Josh 20:7) and the birthplace of Barak (Judg 4:6). The city's role as a refuge city and military muster point reflects its strategic position on the northern Galilean ridge.</p>",
    "38": "<p>Iron, Migdal-el, Horem, Beth-anath, Beth-shemesh — nineteen cities for Naphtali. Beth-anath ('house of Anat') preserves the name of the Canaanite warrior goddess; the failure notice in Judg 1:33 ('Naphtali did not drive out the inhabitants of Beth-shemesh or Beth-anath') explains how Anath's name survived in Israelite territory — they coexisted with those populations rather than eliminating them.</p>",
    "39": "<p>Naphtali's allotment formula. The tribe's subsequent history includes Barak (Judg 4-5), the Galilean leader of the anti-Sisera coalition, and a significant military contribution to Gideon's campaign (Judg 7:23). The later Isaiah passage (Isa 9:1-2) about light coming to Zebulun and Naphtali reflects their status as the most remote, most exposed, and most Gentile-adjacent tribes — the ones most in need of divine rescue.</p>",
    "40": "<p>Dan's allotment: the western foothill zone between Judah and Ephraim, including access to the coastal plain. Dan received prime real estate — the fertile Shephelah and the Aijalon Valley, major transit routes connecting the coastal plain to the hill country. The Samson narratives (Judg 13-16) are set precisely in this territory: Zorah, Eshtaol, Timnah, and Gaza are all Danite cities. The territory's strategic value made it intensely contested by the Philistines.</p>",
    "41": "<p>Zorah and Eshtaol — Samson's hometown and the site of Samson's burial (Judg 16:31). The 'camp of Dan between Zorah and Eshtaol' (Judg 13:25; 18:11-12) where the Spirit first stirred Samson locates the tribe's military assembly point precisely within this allotment. The allotment geography and the Samson narrative are geographically consistent throughout.</p>",
    "42": "<p>Ir-shemesh, Shaalabbin, Aijalon, Ithlah — the Aijalon Valley was the site of the Long Day battle (Josh 10:12) and a major east-west transit corridor. Gezer (v.45 below) controlled the valley's western exit; the entire Aijalon-Sorek system was the main approach from the coastal plain to the Judean hill country, explaining why this territory was contested throughout the biblical period.</p>",
    "43": "<p>Elon, Timnah, Ekron — the border with Philistine territory. Timnah is Samson's wife's hometown (Judg 14:1-2); the repeated Danite-Philistine conflict in Judges 13-16 reflects the geographic reality that Dan's territory directly abutted the Philistine pentapolis. The Philistine pressure on Dan was not incidental but structural — they shared a contested border.</p>",
    "44": "<p>Eltekeh, Gibbethon, Baalath — the coastal cities. Gibbethon is the Philistine city where Israelite kings Nadab (1 Kgs 15:27) and Omri's predecessor Zimri were challenged during military campaigns (1 Kgs 16:15-17) — the allotment city remained on the Philistine-Israelite frontier for centuries, a persistent flashpoint.</p>",
    "45": "<p>Jehud, Bene-berak, Gath-rimmon — the Philistine plain margin. Bene-berak ('sons of lightning') appears in Sennacherib's annals (ANET 287) as a city he conquered during the 701 BCE campaign — Assyrian administrative records confirm the city's existence and location in the coastal zone between Joppa and Ekron.</p>",
    "46": "<p>Me-jarkon and Rakkon with the territory facing Joppa. Joppa (modern Jaffa) is the natural harbor city of the central coast; its appearance as Danite territory reflects the allotment's theoretical claim to the coast. Dan never secured Joppa — the Philistines controlled the coast; Joppa only enters Israelite control under the Maccabees (1 Macc 12:33-34). Peter's vision at Joppa (Acts 10:9-16) is set in a city that was originally allotted to Dan but never possessed by Israel until the Hellenistic period.</p>",
    "47": "<p>'But the Danites had difficulty taking possession of their territory, so they went up and attacked Leshem/Laish, took it... and settled there, calling it Dan.' This single verse summarizes the migration tradition told in detail in Judges 18. The Danite failure to possess their allotted coastal territory — driven out by the Philistines and Amorites — forced the tribe north, where they conquered an isolated Canaanite city. The original Danite territory became effectively absorbed into Philistine and then Judean control; 'Dan' as a northern city became a geographic and cultic landmark (Jeroboam's other golden calf was placed there, 1 Kgs 12:29).</p>",
    "48": "<p>Dan's allotment formula for the original coastal territory. The tribe's split identity — southern allotment never possessed, northern conquest established as a second home — creates the 'from Dan to Beersheba' idiom of the monarchic period, where these two extremes define Israel's entire extent.</p>",
    "49": "<p>'The Israelites gave Joshua son of Nun an inheritance among them.' The leader who spent seven years distributing the land to others finally receives his own portion — and he receives it last. The narrative structure is deliberate: Joshua's personal inheritance is withheld until every tribe has received theirs. The servant-leadership pattern — give first, receive last — is presented without commentary but is unmistakable in the narrative arrangement.</p>",
    "50": "<p>Timnath-serah in the Ephraimite hill country — Joshua's own tribe, his own people. The city is in the Ephraim highlands, away from the contested frontiers; Joshua retires to hill country he has to rebuild ('he rebuilt the city and settled there'). The act of rebuilding connects him to the patriarchal settlers who built altars and wells; Joshua's retirement is itself a form of possession, working the land he was given rather than merely receiving it as a title.</p>",
    "51": "<p>The closing formula for all the Cisjordan allotments: 'at the entrance of the tent of meeting at Shiloh, before the LORD.' The entire distribution process is framed as a liturgical act — the land is received in the presence of YHWH, mediated by priest (Eleazar), commander (Joshua), and tribal elders. The three parties who distributed the land represent the three pillars of Israelite communal life: worship, leadership, and family/clan structure. The formula closes the allotment chapters and marks the book's transition to the subsequent covenant chapters (chs.22-24).</p>"
  },
  "20": {
    "1": "<p>The cities of refuge are established immediately after the allotments are complete — the first communal institution for the new settlement. The command echoes Numbers 35:9-15 and Deuteronomy 19:1-13, which established the theological and legal framework; here Joshua implements what Moses legislated.</p>",
    "2": "<p>The cities of refuge (<em>ʿārê hammiqlāṭ</em>) implement a critical distinction in Israelite homicide law: intentional murder versus accidental killing. The background is the blood avenger (<em>gōʾēl haddām</em>, 'redeemer of the blood') — the nearest male relative of a killed person was legally obligated to execute the killer. This kinship-justice system predated Israel and operated throughout the ancient Near East; the asylum city system modifies it by creating a protected space for inadvertent killers while leaving intentional murderers exposed to the avenger.</p>",
    "3": "<p>The manslayer who kills 'accidentally or unintentionally' (<em>bišgāgāh ûbĕlōʾ-daʿat</em>) — two terms for inadvertence: <em>šĕgāgāh</em> means mistake/accident (Lev 4:2; Num 15:24-29 uses it for unintentional sin); <em>bĕlōʾ-daʿat</em> means without knowledge/forethought. The double qualification emphasizes that the asylum is for genuine accidents, not reckless behavior. Numbers 35:16-21 lists categories of intentional murder (using a weapon, lying in wait, acting with enmity) that do NOT qualify for asylum; the distinction between premeditated and accidental death is one of the most sophisticated elements of Mosaic jurisprudence.</p>",
    "4": "<p>The asylum procedure at the city gate: the fugitive presents his case to the elders of the city. The city gate was the standard judicial forum in ancient Israel (Ruth 4:1-11; Deut 21:19; Prov 31:23; Amos 5:15); the elders there represented the community's legal authority. The procedure requires a hearing — the manslayer is not given automatic protection but must make a case, allowing the elders to evaluate whether the killing was genuinely accidental. The city then receives him into their community.</p>",
    "5": "<p>'If the blood avenger pursues him, they must not hand the accused over.' The city's protection against the avenger is absolute for an inadvertent killer who follows the procedure. The blood avenger (<em>gōʾēl haddām</em>) operated within a recognized legal right; the asylum city system did not abolish it but overrode it for the specific category of accidental death. The tension between kinship-justice (the avenger's right) and communal discernment (the elders' hearing) was a sophisticated legal balance — the system required both the family's right to seek redress and the community's authority to distinguish murder from accident.</p>",
    "6": "<p>'He is to stay in that city until he has stood trial before the congregation, and until the death of the high priest.' Two release conditions: (1) a formal trial before the assembly (<em>ʿādāh</em>) — the same body that ratified the Gibeonite treaty (Josh 9:15-21); (2) the death of the incumbent high priest. The high priest's death as a release mechanism is unique in ancient law — there is no ANE parallel. Rabbinic tradition interpreted it as an expiatory death: the high priest's death atones for the blood that was shed, even inadvertently, releasing the manslayer from further liability. The high priest's death-as-expiation is a powerful typological structure that points toward Hebrews' reading of Christ's death as the permanent high-priestly atonement.</p>",
    "7": "<p>Three western cities of refuge: Kedesh in Galilee (Naphtali), Shechem in the hill country of Ephraim, and Kiriath-arba/Hebron in the hill country of Judah. The three cities are distributed geographically: north, center, and south. This placement was deliberate and explicitly commanded in Deut 19:3 ('you shall prepare the roads... so that anyone who kills a person may flee there'). The roads to the cities were supposed to be maintained and clearly marked; Rabbinic tradition (Sifre Deut 186) says the roads were kept wide and the signs well-maintained. Geographic accessibility was a justice concern — a system requiring a long journey to reach asylum was a system that would fail the innocent.</p>",
    "8": "<p>Three eastern cities of refuge: Bezer in the plateau of Reuben, Ramoth in Gilead from Gad, and Golan in Bashan from half-Manasseh. The symmetrical distribution (three east, three west) provided access for the entire land, with no region more than a day's travel from an asylum city. Bezer is in the Moabite plateau; Ramoth-Gilead (1 Kgs 22:3,29; 2 Kgs 8:28; 9:14) became a major military site in the Syrian wars — the city of refuge eventually became the most contested fortress on Israel's eastern frontier.</p>",
    "9": "<p>'These were the designated cities for all the Israelites and for the foreigners living among them' — the asylum system extended to resident aliens (<em>gēr</em>) as well as native Israelites. The extension to foreigners is explicitly commanded in Num 35:15 and reflects the egalitarian principle that the same law applies to native and stranger alike (Num 15:15-16; Lev 24:22). This is not merely administrative policy but theological: YHWH's justice does not discriminate between citizens and residents. The cities of refuge were a social institution that embodied the covenant's ethic of equal justice — an ethic that the NT presents as fulfilled in Christ, the permanent refuge for all who flee to him.</p>"
  }
}


def main():
    existing = load_comm('mkt-context', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-context', 'joshua', existing)

    il = json.loads((ROOT / 'data/interlinear/joshua.json').read_text())
    all_ok = True
    for ch in range(18, 21):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present ✓')
    chs = sorted(existing.keys(), key=int)
    print(f'Joshua mkt-context chapters now: {chs} ({len(chs)}/24)')


if __name__ == '__main__':
    main()
